import { getQueueToken } from '@nestjs/bullmq';
import { Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { JiraChangelogModel } from '@modules/jira/db/jira-changelog.model';
import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
import { JiraIssueModel } from '@modules/jira/db/jira-issues.model';
import { JiraProjectModel } from '@modules/jira/db/jira-projects.model';
import { JiraSprintModel } from '@modules/jira/db/jira-sprints.model';
import { JiraWorklogModel } from '@modules/jira/db/jira-worklogs.model';
import { JiraApiService } from '@modules/jira/jira-api.service';
import { JiraSyncService } from '@modules/jira/jira-sync.service';
import {
	IJiraInstallationBase,
	IJiraProjectBase,
	JiraInstallationStatus,
} from '@modules/jira/types/jira-installation.interface';

const mockInstallation: IJiraInstallationBase = {
	_id: 'install-1',
	company_id: 'company-1',
	cloud_id: 'cloud-abc',
	site_url: 'https://acme.atlassian.net',
	access_token: 'token',
	refresh_token: 'refresh',
	token_expires_at: new Date(Date.now() + 3600000),
	status: JiraInstallationStatus.ACTIVE,
	created_at: new Date(),
	updated_at: new Date(),
};

const mockProject: IJiraProjectBase = {
	_id: 'proj-1',
	installation_id: 'install-1',
	project_key: 'ENG',
	project_id: '10000',
	name: 'Engineering',
	project_type: 'software',
	last_synced_at: null,
	created_at: new Date(),
	updated_at: new Date(),
};

const mockInstallationModel = {
	findById: jest.fn(),
	findAllActive: jest.fn(),
};
const mockProjectModel = {
	upsertMany: jest.fn(),
	findByInstallationId: jest.fn(),
	updateLastSyncedAt: jest.fn(),
};
const mockIssueModel = { upsertMany: jest.fn() };
const mockChangelogModel = { upsertMany: jest.fn() };
const mockWorklogModel = { upsertMany: jest.fn() };
const mockSprintModel = { upsertMany: jest.fn() };
const mockJiraApiService = {
	getValidToken: jest.fn(),
	listProjects: jest.fn(),
	searchIssues: jest.fn(),
	getWorklogsForIssue: jest.fn(),
	listBoards: jest.fn(),
	listSprints: jest.fn(),
};
const mockQueue = { add: jest.fn() };

describe('JiraSyncService', () => {
	let service: JiraSyncService;

	beforeEach(async () => {
		jest.clearAllMocks();

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				JiraSyncService,
				{ provide: JiraInstallationModel, useValue: mockInstallationModel },
				{ provide: JiraProjectModel, useValue: mockProjectModel },
				{ provide: JiraIssueModel, useValue: mockIssueModel },
				{ provide: JiraChangelogModel, useValue: mockChangelogModel },
				{ provide: JiraWorklogModel, useValue: mockWorklogModel },
				{ provide: JiraSprintModel, useValue: mockSprintModel },
				{ provide: JiraApiService, useValue: mockJiraApiService },
				{ provide: getQueueToken('jira'), useValue: mockQueue },
			],
		}).compile();

		service = module.get<JiraSyncService>(JiraSyncService);

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'debug').mockImplementation(jest.fn());
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(service).toBeDefined();
	});

	describe('discoverProjects', () => {
		it('should skip when installation not found', async () => {
			mockInstallationModel.findById.mockResolvedValue(null);

			await service.discoverProjects({ installationDbId: 'install-1' });

			expect(mockJiraApiService.listProjects).not.toHaveBeenCalled();
		});

		it('should upsert projects and enqueue sync_project per project', async () => {
			mockInstallationModel.findById.mockResolvedValue(mockInstallation);
			mockJiraApiService.getValidToken.mockResolvedValue('token');
			mockJiraApiService.listProjects.mockResolvedValue([
				{ id: '10000', key: 'ENG', name: 'Engineering', projectTypeKey: 'software' },
			]);
			mockProjectModel.upsertMany.mockResolvedValue(undefined);
			mockProjectModel.findByInstallationId.mockResolvedValue([mockProject]);
			mockQueue.add.mockResolvedValue(undefined);

			await service.discoverProjects({ installationDbId: 'install-1' });

			expect(mockProjectModel.upsertMany).toHaveBeenCalled();
			expect(mockQueue.add).toHaveBeenCalledWith(
				'sync_project',
				expect.objectContaining({ projectDbId: mockProject._id }),
				expect.any(Object),
			);
		});
	});

	describe('pollAllInstallations', () => {
		it('should enqueue discover_projects for all active installations', async () => {
			mockInstallationModel.findAllActive.mockResolvedValue([mockInstallation]);
			mockQueue.add.mockResolvedValue(undefined);

			await service.pollAllInstallations();

			expect(mockQueue.add).toHaveBeenCalledWith(
				'discover_projects',
				{ installationDbId: mockInstallation._id },
				expect.any(Object),
			);
		});

		it('should handle empty installations list', async () => {
			mockInstallationModel.findAllActive.mockResolvedValue([]);
			mockQueue.add.mockResolvedValue(undefined);

			await service.pollAllInstallations();

			expect(mockQueue.add).not.toHaveBeenCalled();
		});
	});
});
