import { Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';
import { Job } from 'bullmq';

import { JiraProcessor } from '@modules/jira/jira-processor.service';
import { JiraSyncService } from '@modules/jira/jira-sync.service';

const mockSyncService = {
	pollAllInstallations: jest.fn(),
	discoverProjects: jest.fn(),
	syncProject: jest.fn(),
};

const makeJob = (name: string, data: unknown): Job =>
	({ id: 'job-1', name, data } as unknown as Job);

describe('JiraProcessor', () => {
	let processor: JiraProcessor;

	beforeEach(async () => {
		jest.clearAllMocks();

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				JiraProcessor,
				{ provide: JiraSyncService, useValue: mockSyncService },
			],
		}).compile();

		processor = module.get<JiraProcessor>(JiraProcessor);

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'debug').mockImplementation(jest.fn());
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(processor).toBeDefined();
	});

	it('should route poll_installations to syncService.pollAllInstallations', async () => {
		mockSyncService.pollAllInstallations.mockResolvedValue(undefined);

		await processor.process(makeJob('poll_installations', { triggeredAt: '2026-01-01' }));

		expect(mockSyncService.pollAllInstallations).toHaveBeenCalled();
	});

	it('should route discover_projects to syncService.discoverProjects', async () => {
		mockSyncService.discoverProjects.mockResolvedValue(undefined);

		await processor.process(
			makeJob('discover_projects', { installationDbId: 'install-1' }),
		);

		expect(mockSyncService.discoverProjects).toHaveBeenCalledWith({
			installationDbId: 'install-1',
		});
	});

	it('should route sync_project to syncService.syncProject', async () => {
		mockSyncService.syncProject.mockResolvedValue(undefined);

		await processor.process(
			makeJob('sync_project', {
				installationDbId: 'install-1',
				projectDbId: 'proj-1',
				projectKey: 'ENG',
			}),
		);

		expect(mockSyncService.syncProject).toHaveBeenCalledWith({
			installationDbId: 'install-1',
			projectDbId: 'proj-1',
			projectKey: 'ENG',
		});
	});

	it('should throw and log when job throws', async () => {
		mockSyncService.pollAllInstallations.mockRejectedValue(new Error('sync error'));

		await expect(
			processor.process(makeJob('poll_installations', {})),
		).rejects.toThrow('sync error');
	});

	it('should warn on unknown job name', async () => {
		const warnSpy = jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());

		await processor.process(makeJob('unknown_job', {}));

		expect(warnSpy).toHaveBeenCalled();
	});
});
