17	import { JIRA_CLIENT_ID, JIRA_CLIENT_SECRET, JIRA_CALLBACK_URL } from '@constants/env-variables.constant';
18	
19	const TOKEN_REFRESH_BUFFER_MS = 5 * 60 * 1000;
20	const ATLASSIAN_TOKEN_URL = 'https://auth.atlassian.com/oauth/token';
21	const ATLASSIAN_RESOURCES_URL = 'https://api.atlassian.com/oauth/token/accessible-resources';
22	
23	@Injectable()
24	export class JiraApiService {
