203		private async storeChangelogs({
204			installationDbId,
205			issues,
206			savedIssues,
207		}: {
208			installationDbId: string;
209			issues: IJiraApiIssue[];
210			savedIssues: IJiraIssueBase[];
211		}): Promise<void> {
212			const issueDbIdMap = new Map(savedIssues.map((i) => [i.issue_id, i._id]));
213			const entries: Array<{
214				issue_id: string;
215				installation_id: string;
216				jira_history_id: string;
217				author_id: string | null;
218				field: string;
219				from_value: string | null;
220				to_value: string | null;
221				changed_at: Date;
222			}> = [];
223	
224			for (const issue of issues) {
225				const issueDbId = issueDbIdMap.get(issue.id);
226				if (!issueDbId || !issue.changelog) continue;
227	
228				for (const history of issue.changelog.histories) {
229					for (const item of history.items) {
230						entries.push({
231							issue_id: issueDbId,
232							installation_id: installationDbId,
233							jira_history_id: history.id,
234							author_id: history.author?.accountId ?? null,
235							field: item.field,
236							from_value: item.fromString,
237							to_value: item.toString,
238							changed_at: new Date(history.created),
239						});
240					}
241				}
242			}
243	
244			await this.changelogModel.upsertMany({ entries });
245		}
246	
247		private async storeWorklogs({
248			installationDbId,
249			cloudId,
250			token,
251			issues,
252			savedIssues,
253		}: {
254			installationDbId: string;
255			cloudId: string;
256			token: string;
257			issues: IJiraApiIssue[];
258			savedIssues: IJiraIssueBase[];
259		}): Promise<void> {
260			const issueDbIdMap = new Map(savedIssues.map((i) => [i.issue_id, i._id]));
261	
262			for (const issue of issues) {
263				const issueDbId = issueDbIdMap.get(issue.id);
264				if (!issueDbId) continue;
265	
266				const worklogs = await this.jiraApiService.getWorklogsForIssue({
267					cloudId,
268					token,
269					issueId: issue.id,
270				});
271	
272				if (worklogs.length === 0) continue;
273	
274				await this.worklogModel.upsertMany({
275					worklogs: worklogs.map((w) => ({
276						issue_id: issueDbId,
277						installation_id: installationDbId,
278						jira_worklog_id: w.id,
279						author_id: w.author?.accountId ?? null,
280						time_spent_sec: w.timeSpentSeconds,
281						started_at: w.started ? new Date(w.started) : null,
282						updated_at: new Date(w.updated),
283					})),
284				});
285			}
286		}
