288		private async fetchAndStoreSprints({
289			installationDbId,
290			projectKey,
291			cloudId,
292			token,
293		}: {
294			installationDbId: string;
295			projectKey: string;
296			cloudId: string;
297			token: string;
298		}): Promise<void> {
299			try {
300				const boardsResponse = await this.jiraApiService.listBoards({
301					cloudId,
302					token,
303					projectKeyOrId: projectKey,
304				});
305	
306				for (const board of boardsResponse.values) {
307					let startAt = 0;
308					while (true) {
309						const sprintResponse = await this.jiraApiService.listSprints({
310							cloudId,
311							token,
312							boardId: board.id,
313							startAt,
314						});
315	
316						await this.sprintModel.upsertMany({
317							installationId: installationDbId,
318							boardId: String(board.id),
319							sprints: sprintResponse.values,
320						});
321	
322						if (sprintResponse.isLast || sprintResponse.values.length === 0) break;
323						startAt += 50;
324					}
325				}
326			} catch (error) {
327				this.logger.warn(
328					`Failed to fetch sprints for project ${projectKey}: ${(error as Error).message}`,
329				);
330			}
331		}
332	}
