import { Test, TestingModule } from '@nestjs/testing';

import { CacheService } from '@modules/cache/cache.service';
import { Namespaces } from '@modules/cache/types/cache.interface';
import { EnvConfigService } from '@modules/env-config/env-config.service';
import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
import { JiraApiService } from '@modules/jira/jira-api.service';
import { JiraInstallService } from '@modules/jira/jira-install.service';
import {
	IJiraInstallationBase,
	JiraInstallationStatus,
} from '@modules/jira/types/jira-installation.interface';

const mockInstallation: IJiraInstallationBase = {
	_id: 'install-uuid-1',
	company_id: 'company-uuid-1',
	cloud_id: 'cloud-abc123',
	site_url: 'https://acme.atlassian.net',
	access_token: 'access-token',
	refresh_token: 'refresh-token',
	token_expires_at: new Date(Date.now() + 3600000),
	status: JiraInstallationStatus.ACTIVE,
	created_at: new Date(),
	updated_at: new Date(),
};

const mockConfigService = { get: jest.fn() };
const mockCacheService = { get: jest.fn(), set: jest.fn(), deleteOne: jest.fn() };
const mockJiraApiService = {
	exchangeCode: jest.fn(),
	getAccessibleResources: jest.fn(),
};
const mockInstallationModel = { create: jest.fn(), markUninstalled: jest.fn() };
const mockQueue = { add: jest.fn() };

describe('JiraInstallService', () => {
	let service: JiraInstallService;

	beforeEach(async () => {
		jest.clearAllMocks();

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				JiraInstallService,
				{ provide: EnvConfigService, useValue: mockConfigService },
				{ provide: CacheService, useValue: mockCacheService },
				{ provide: JiraApiService, useValue: mockJiraApiService },
				{ provide: JiraInstallationModel, useValue: mockInstallationModel },
				{ provide: getQueueToken('jira'), useValue: mockQueue },
			],
		}).compile();

		service = module.get<JiraInstallService>(JiraInstallService);

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'debug').mockImplementation(jest.fn());
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(service).toBeDefined();
	});

	describe('initiateConnect', () => {
		it('should store state in cache and return Atlassian OAuth URL', async () => {
			mockConfigService.get
				.mockReturnValueOnce('my-client-id')
				.mockReturnValueOnce('https://myapp.com/jira/callback');
			mockCacheService.set.mockResolvedValue(undefined);

			const url = await service.initiateConnect({
				companyId: 'company-uuid-1',
				userId: 'user-uuid-1',
			});

			expect(mockCacheService.set).toHaveBeenCalledWith(
				expect.objectContaining({ namespace: Namespaces.JIRA_INSTALL_STATE }),
			);
			expect(url).toContain('https://auth.atlassian.com/authorize');
			expect(url).toContain('my-client-id');
		});

		it('should throw when cache set fails', async () => {
			mockConfigService.get.mockReturnValue('val');
			mockCacheService.set.mockRejectedValue(new Error('cache error'));

			await expect(
				service.initiateConnect({ companyId: 'company-uuid-1', userId: 'user-uuid-1' }),
			).rejects.toThrow('cache error');
		});
	});

	describe('handleCallback', () => {
		it('should throw BadRequestException when state is invalid', async () => {
			mockCacheService.get.mockResolvedValue(null);

			await expect(
				service.handleCallback({ code: 'auth-code', state: 'invalid-state' }),
			).rejects.toThrow(BadRequestException);
		});

		it('should throw BadRequestException when no Jira resources found', async () => {
			mockCacheService.get.mockResolvedValue({ companyId: 'company-1', userId: 'user-1' });
			mockCacheService.deleteOne.mockResolvedValue(true);
			mockJiraApiService.exchangeCode.mockResolvedValue({
				access_token: 'at',
				refresh_token: 'rt',
				expires_in: 3600,
			});
			mockJiraApiService.getAccessibleResources.mockResolvedValue([]);

			await expect(
				service.handleCallback({ code: 'auth-code', state: 'valid-state' }),
			).rejects.toThrow(BadRequestException);
		});

		it('should create installation and enqueue discover_projects on valid callback', async () => {
			mockCacheService.get.mockResolvedValue({ companyId: 'company-1', userId: 'user-1' });
			mockCacheService.deleteOne.mockResolvedValue(true);
			mockJiraApiService.exchangeCode.mockResolvedValue({
				access_token: 'at',
				refresh_token: 'rt',
				expires_in: 3600,
			});
			mockJiraApiService.getAccessibleResources.mockResolvedValue([
				{ id: 'cloud-abc', url: 'https://acme.atlassian.net', name: 'Acme' },
			]);
			mockInstallationModel.create.mockResolvedValue(mockInstallation);
			mockQueue.add.mockResolvedValue(undefined);

			const result = await service.handleCallback({ code: 'auth-code', state: 'valid-state' });

			expect(mockInstallationModel.create).toHaveBeenCalled();
			expect(mockQueue.add).toHaveBeenCalledWith(
				'discover_projects',
				{ installationDbId: mockInstallation._id },
				expect.any(Object),
			);
			expect(result).toEqual(mockInstallation);
		});
	});

	describe('disconnect', () => {
		it('should delegate to installationModel.markUninstalled', async () => {
			mockInstallationModel.markUninstalled.mockResolvedValue(undefined);

			await service.disconnect({
				installationDbId: mockInstallation._id,
				companyId: mockInstallation.company_id,
			});

			expect(mockInstallationModel.markUninstalled).toHaveBeenCalledWith({
				id: mockInstallation._id,
				companyId: mockInstallation.company_id,
			});
		});

		it('should throw when model throws', async () => {
			mockInstallationModel.markUninstalled.mockRejectedValue(new Error('db error'));

			await expect(
				service.disconnect({
					installationDbId: mockInstallation._id,
					companyId: mockInstallation.company_id,
				}),
			).rejects.toThrow('db error');
		});
	});
});

import { HttpService } from '@nestjs/axios';
import { Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { EnvConfigService } from '@modules/env-config/env-config.service';
import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
import { JiraApiService } from '@modules/jira/jira-api.service';
import {
	IJiraInstallationBase,
	JiraInstallationStatus,
} from '@modules/jira/types/jira-installation.interface';

const baseInstallation: IJiraInstallationBase = {
	_id: 'install-1',
	company_id: 'company-1',
	cloud_id: 'cloud-abc',
	site_url: 'https://acme.atlassian.net',
	access_token: 'valid-token',
	refresh_token: 'refresh-token',
	token_expires_at: new Date(Date.now() + 3600000),
	status: JiraInstallationStatus.ACTIVE,
	created_at: new Date(),
	updated_at: new Date(),
};

const mockHttp = { axiosRef: { get: jest.fn(), post: jest.fn() } };
const mockConfig = { get: jest.fn() };
const mockInstallationModel = {
	updateTokens: jest.fn(),
	markNeedsReauth: jest.fn(),
};

describe('JiraApiService', () => {
	let service: JiraApiService;

	beforeEach(async () => {
		jest.clearAllMocks();

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				JiraApiService,
				{ provide: HttpService, useValue: mockHttp },
				{ provide: EnvConfigService, useValue: mockConfig },
				{ provide: JiraInstallationModel, useValue: mockInstallationModel },
			],
		}).compile();

		service = module.get<JiraApiService>(JiraApiService);

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'debug').mockImplementation(jest.fn());
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(service).toBeDefined();
	});

	describe('getValidToken', () => {
		it('should return existing token when not expired', async () => {
			const token = await service.getValidToken({ installation: baseInstallation });
			expect(token).toBe('valid-token');
			expect(mockHttp.axiosRef.post).not.toHaveBeenCalled();
		});

		it('should refresh token when near expiry', async () => {
			const expiredInstallation: IJiraInstallationBase = {
				...baseInstallation,
				token_expires_at: new Date(Date.now() + 60000),
			};

			mockConfig.get.mockReturnValue('client-id');
			mockHttp.axiosRef.post.mockResolvedValue({
				data: {
					access_token: 'new-token',
					refresh_token: 'new-refresh',
					expires_in: 3600,
				},
			});
			mockInstallationModel.updateTokens.mockResolvedValue(undefined);

			const token = await service.getValidToken({ installation: expiredInstallation });

			expect(token).toBe('new-token');
			expect(mockInstallationModel.updateTokens).toHaveBeenCalledWith(
				expect.objectContaining({ id: expiredInstallation._id, accessToken: 'new-token' }),
			);
		});

		it('should mark needs_reauth and throw when refresh fails', async () => {
			const expiredInstallation: IJiraInstallationBase = {
				...baseInstallation,
				token_expires_at: new Date(Date.now() + 60000),
			};

			mockConfig.get.mockReturnValue('client-id');
			mockHttp.axiosRef.post.mockRejectedValue(new Error('token refresh failed'));
			mockInstallationModel.markNeedsReauth.mockResolvedValue(undefined);

			await expect(
				service.getValidToken({ installation: expiredInstallation }),
			).rejects.toThrow('token refresh failed');

			expect(mockInstallationModel.markNeedsReauth).toHaveBeenCalledWith({
				id: expiredInstallation._id,
			});
		});
	});

	describe('listProjects', () => {
		it('should paginate and collect all projects', async () => {
			mockHttp.axiosRef.get
				.mockResolvedValueOnce({
					data: { values: [{ id: '1', key: 'ENG', name: 'Engineering', projectTypeKey: 'software' }], isLast: false },
				})
				.mockResolvedValueOnce({
					data: { values: [{ id: '2', key: 'OPS', name: 'Ops', projectTypeKey: 'software' }], isLast: true },
				});

			const projects = await service.listProjects({ cloudId: 'cloud-1', token: 'tok' });

			expect(projects).toHaveLength(2);
			expect(mockHttp.axiosRef.get).toHaveBeenCalledTimes(2);
		});

		it('should stop pagination when values array is empty', async () => {
			mockHttp.axiosRef.get.mockResolvedValueOnce({
				data: { values: [], isLast: false },
			});

			const projects = await service.listProjects({ cloudId: 'cloud-1', token: 'tok' });

			expect(projects).toHaveLength(0);
			expect(mockHttp.axiosRef.get).toHaveBeenCalledTimes(1);
		});
	});
});

import { getQueueToken } from '@nestjs/bullmq';
import { Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { JiraChangelogModel } from '@modules/jira/db/jira-changelog.model';
import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
import { JiraIssueModel } from '@modules/jira/db/jira-issues.model';
import { JiraProjectModel } from '@modules/jira/db/jira-projects.model';
import { JiraSprintModel } from '@modules/jira/db/jira-sprints.model';
import { JiraWorklogModel } from '@modules/jira/db/jira-worklogs.model';
import { JiraApiService } from '@modules/jira/jira-api.service';
import { JiraSyncService } from '@modules/jira/jira-sync.service';
import {
	IJiraInstallationBase,
	IJiraIssueBase,
	IJiraProjectBase,
	JiraInstallationStatus,
} from '@modules/jira/types/jira-installation.interface';

const mockInstallation: IJiraInstallationBase = {
	_id: 'install-1',
	company_id: 'company-1',
	cloud_id: 'cloud-abc',
	site_url: 'https://acme.atlassian.net',
	access_token: 'token',
	refresh_token: 'refresh',
	token_expires_at: new Date(Date.now() + 3600000),
	status: JiraInstallationStatus.ACTIVE,
	created_at: new Date(),
	updated_at: new Date(),
};

const mockProject: IJiraProjectBase = {
	_id: 'proj-1',
	installation_id: 'install-1',
	project_key: 'ENG',
	project_id: '10000',
	name: 'Engineering',
	project_type: 'software',
	last_synced_at: null,
	created_at: new Date(),
	updated_at: new Date(),
};

const mockSavedIssue: IJiraIssueBase = {
	_id: 'issue-db-1',
	project_id: 'proj-1',
	installation_id: 'install-1',
	issue_key: 'ENG-1',
	issue_id: 'jira-issue-1',
	issue_type: 'Story',
	status: 'In Progress',
	priority: 'Medium',
	assignee_id: 'user-1',
	reporter_id: 'user-2',
	story_points: 3,
	created_at: new Date(),
	updated_at: new Date(),
	resolved_at: null,
};

const mockInstallationModel = {
	findById: jest.fn(),
	findAllActive: jest.fn(),
};
const mockProjectModel = {
	upsertMany: jest.fn(),
	findByInstallationId: jest.fn(),
	updateLastSyncedAt: jest.fn(),
};
const mockIssueModel = { upsertMany: jest.fn() };
const mockChangelogModel = { upsertMany: jest.fn() };
const mockWorklogModel = { upsertMany: jest.fn() };
const mockSprintModel = { upsertMany: jest.fn() };
const mockJiraApiService = {
	getValidToken: jest.fn(),
	listProjects: jest.fn(),
	searchIssues: jest.fn(),
	getWorklogsForIssue: jest.fn(),
	listBoards: jest.fn(),
	listSprints: jest.fn(),
};
const mockQueue = { add: jest.fn() };

describe('JiraSyncService', () => {
	let service: JiraSyncService;

	beforeEach(async () => {
		jest.clearAllMocks();

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				JiraSyncService,
				{ provide: JiraInstallationModel, useValue: mockInstallationModel },
				{ provide: JiraProjectModel, useValue: mockProjectModel },
				{ provide: JiraIssueModel, useValue: mockIssueModel },
				{ provide: JiraChangelogModel, useValue: mockChangelogModel },
				{ provide: JiraWorklogModel, useValue: mockWorklogModel },
				{ provide: JiraSprintModel, useValue: mockSprintModel },
				{ provide: JiraApiService, useValue: mockJiraApiService },
				{ provide: getQueueToken('jira'), useValue: mockQueue },
			],
		}).compile();

		service = module.get<JiraSyncService>(JiraSyncService);

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'debug').mockImplementation(jest.fn());
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(service).toBeDefined();
	});

	describe('discoverProjects', () => {
		it('should skip when installation not found', async () => {
			mockInstallationModel.findById.mockResolvedValue(null);

			await service.discoverProjects({ installationDbId: 'install-1' });

			expect(mockJiraApiService.listProjects).not.toHaveBeenCalled();
		});

		it('should upsert projects and enqueue sync_project per project', async () => {
			mockInstallationModel.findById.mockResolvedValue(mockInstallation);
			mockJiraApiService.getValidToken.mockResolvedValue('token');
			mockJiraApiService.listProjects.mockResolvedValue([
				{ id: '10000', key: 'ENG', name: 'Engineering', projectTypeKey: 'software' },
			]);
			mockProjectModel.upsertMany.mockResolvedValue(undefined);
			mockProjectModel.findByInstallationId.mockResolvedValue([mockProject]);
			mockQueue.add.mockResolvedValue(undefined);

			await service.discoverProjects({ installationDbId: 'install-1' });

			expect(mockProjectModel.upsertMany).toHaveBeenCalled();
			expect(mockQueue.add).toHaveBeenCalledWith(
				'sync_project',
				expect.objectContaining({ projectDbId: mockProject._id }),
				expect.any(Object),
			);
		});

		it('should enqueue sync_project with all required fields', async () => {
			mockInstallationModel.findById.mockResolvedValue(mockInstallation);
			mockJiraApiService.getValidToken.mockResolvedValue('token');
			mockJiraApiService.listProjects.mockResolvedValue([]);
			mockProjectModel.upsertMany.mockResolvedValue(undefined);
			mockProjectModel.findByInstallationId.mockResolvedValue([mockProject]);
			mockQueue.add.mockResolvedValue(undefined);

			await service.discoverProjects({ installationDbId: 'install-1' });

			expect(mockQueue.add).toHaveBeenCalledWith(
				'sync_project',
				expect.objectContaining({
					installationDbId: 'install-1',
					projectDbId: mockProject._id,
					projectKey: mockProject.project_key,
					projectId: mockProject.project_id,
				}),
				expect.any(Object),
			);
		});
	});

	describe('pollAllInstallations', () => {
		it('should enqueue discover_projects for all active installations', async () => {
			mockInstallationModel.findAllActive.mockResolvedValue([mockInstallation]);
			mockQueue.add.mockResolvedValue(undefined);

			await service.pollAllInstallations();

			expect(mockQueue.add).toHaveBeenCalledWith(
				'discover_projects',
				{ installationDbId: mockInstallation._id },
				expect.any(Object),
			);
		});

		it('should handle empty installations list', async () => {
			mockInstallationModel.findAllActive.mockResolvedValue([]);
			mockQueue.add.mockResolvedValue(undefined);

			await service.pollAllInstallations();

			expect(mockQueue.add).not.toHaveBeenCalled();
		});
	});

	describe('syncProject', () => {
		it('should skip when installation not found', async () => {
			mockInstallationModel.findById.mockResolvedValue(null);

			await service.syncProject({
				installationDbId: 'install-1',
				projectDbId: 'proj-1',
				projectKey: 'ENG',
			});

			expect(mockJiraApiService.getValidToken).not.toHaveBeenCalled();
		});

		it('should skip when project not found', async () => {
			mockInstallationModel.findById.mockResolvedValue(mockInstallation);
			mockProjectModel.findByInstallationId.mockResolvedValue([]);

			await service.syncProject({
				installationDbId: 'install-1',
				projectDbId: 'proj-999',
				projectKey: 'ENG',
			});

			expect(mockJiraApiService.getValidToken).not.toHaveBeenCalled();
		});

		it('should sync issues, changelogs, worklogs, and sprints for a found project', async () => {
			const mockIssue = {
				id: 'jira-issue-1',
				key: 'ENG-1',
				fields: {
					issuetype: { name: 'Story' },
					status: { name: 'In Progress' },
					priority: { name: 'Medium' },
					assignee: { accountId: 'user-1' },
					reporter: { accountId: 'user-2' },
					customfield_10016: 3,
					updated: new Date().toISOString(),
					resolutiondate: null,
				},
				changelog: { histories: [] },
			};

			mockInstallationModel.findById.mockResolvedValue(mockInstallation);
			mockProjectModel.findByInstallationId.mockResolvedValue([mockProject]);
			mockJiraApiService.getValidToken.mockResolvedValue('token');
			mockJiraApiService.searchIssues
				.mockResolvedValueOnce({ issues: [mockIssue], total: 1 })
				.mockResolvedValueOnce({ issues: [], total: 0 });
			mockIssueModel.upsertMany.mockResolvedValue([mockSavedIssue]);
			mockChangelogModel.upsertMany.mockResolvedValue(undefined);
			mockJiraApiService.getWorklogsForIssue.mockResolvedValue([]);
			mockJiraApiService.listBoards.mockResolvedValue({ values: [] });
			mockProjectModel.updateLastSyncedAt.mockResolvedValue(undefined);

			await service.syncProject({
				installationDbId: 'install-1',
				projectDbId: 'proj-1',
				projectKey: 'ENG',
			});

			expect(mockIssueModel.upsertMany).toHaveBeenCalled();
			expect(mockProjectModel.updateLastSyncedAt).toHaveBeenCalledWith({ id: 'proj-1' });
		});

		it('should use last_synced_at when project has been previously synced', async () => {
			const syncedProject: IJiraProjectBase = {
				...mockProject,
				last_synced_at: new Date('2026-01-01'),
			};

			mockInstallationModel.findById.mockResolvedValue(mockInstallation);
			mockProjectModel.findByInstallationId.mockResolvedValue([syncedProject]);
			mockJiraApiService.getValidToken.mockResolvedValue('token');
			mockJiraApiService.searchIssues.mockResolvedValue({ issues: [], total: 0 });
			mockJiraApiService.listBoards.mockResolvedValue({ values: [] });
			mockProjectModel.updateLastSyncedAt.mockResolvedValue(undefined);

			await service.syncProject({
				installationDbId: 'install-1',
				projectDbId: 'proj-1',
				projectKey: 'ENG',
			});

			expect(mockJiraApiService.searchIssues).toHaveBeenCalledWith(
				expect.objectContaining({ jql: expect.stringContaining('2026-01-01') }),
			);
		});

		it('should warn but not throw when sprint fetch fails', async () => {
			mockInstallationModel.findById.mockResolvedValue(mockInstallation);
			mockProjectModel.findByInstallationId.mockResolvedValue([mockProject]);
			mockJiraApiService.getValidToken.mockResolvedValue('token');
			mockJiraApiService.searchIssues.mockResolvedValue({ issues: [], total: 0 });
			mockJiraApiService.listBoards.mockRejectedValue(new Error('boards API error'));
			mockProjectModel.updateLastSyncedAt.mockResolvedValue(undefined);

			await expect(
				service.syncProject({
					installationDbId: 'install-1',
					projectDbId: 'proj-1',
					projectKey: 'ENG',
				}),
			).resolves.toBeUndefined();

			expect(mockProjectModel.updateLastSyncedAt).toHaveBeenCalled();
		});

		it('should store worklogs when returned by API', async () => {
			const mockIssue = {
				id: 'jira-issue-1',
				key: 'ENG-1',
				fields: {
					issuetype: { name: 'Story' },
					status: { name: 'Done' },
					priority: { name: 'High' },
					assignee: null,
					reporter: null,
					customfield_10016: null,
					updated: new Date().toISOString(),
					resolutiondate: new Date().toISOString(),
				},
				changelog: { histories: [] },
			};

			const mockWorklog = {
				id: 'wl-1',
				author: { accountId: 'user-1' },
				timeSpentSeconds: 3600,
				started: new Date().toISOString(),
				updated: new Date().toISOString(),
			};

			mockInstallationModel.findById.mockResolvedValue(mockInstallation);
			mockProjectModel.findByInstallationId.mockResolvedValue([mockProject]);
			mockJiraApiService.getValidToken.mockResolvedValue('token');
			mockJiraApiService.searchIssues
				.mockResolvedValueOnce({ issues: [mockIssue], total: 1 })
				.mockResolvedValueOnce({ issues: [], total: 0 });
			mockIssueModel.upsertMany.mockResolvedValue([mockSavedIssue]);
			mockChangelogModel.upsertMany.mockResolvedValue(undefined);
			mockJiraApiService.getWorklogsForIssue.mockResolvedValue([mockWorklog]);
			mockWorklogModel.upsertMany.mockResolvedValue(undefined);
			mockJiraApiService.listBoards.mockResolvedValue({ values: [] });
			mockProjectModel.updateLastSyncedAt.mockResolvedValue(undefined);

			await service.syncProject({
				installationDbId: 'install-1',
				projectDbId: 'proj-1',
				projectKey: 'ENG',
			});

			expect(mockWorklogModel.upsertMany).toHaveBeenCalled();
		});

		it('should store changelogs when issue has changelog histories', async () => {
			const mockIssue = {
				id: 'jira-issue-1',
				key: 'ENG-1',
				fields: {
					issuetype: { name: 'Story' },
					status: { name: 'Done' },
					priority: null,
					assignee: null,
					reporter: null,
